(function(){const rootId='job-correlation-widget';const bridge=window.MorphyBridge;if(!bridge){return;}const palette=['#8df0c6','#5ec3a7','#38a68b','#1f7265','#0d5b55','#08433f','#031f1a'];function polarToCartesian(cx,cy,radius,angleDeg){const angleRad=(angleDeg-90)*Math.PI/180;return{x:cx+radius*Math.cos(angleRad),y:cy+radius*Math.sin(angleRad)};}function describeArc(cx,cy,radius,startAngle,endAngle){const start=polarToCartesian(cx,cy,radius,endAngle);const end=polarToCartesian(cx,cy,radius,startAngle);const largeArcFlag=endAngle-startAngle<=180?'0':'1';return`M ${start.x} ${start.y} A ${radius} ${radius} 0 ${largeArcFlag} 0 ${end.x} ${end.y}`;}function buildDonut(chartData){const layout=document.createElement('div');layout.className='donut-layout';const donut=document.createElement('div');donut.className='donut-visual';const svg=document.createElementNS('http://www.w3.org/2000/svg','svg');svg.setAttribute('viewBox','0 0 200 200');const ring=document.createElementNS('http://www.w3.org/2000/svg','circle');ring.setAttribute('cx','100');ring.setAttribute('cy','100');ring.setAttribute('r','72');ring.setAttribute('fill','none');ring.setAttribute('stroke','rgba(14, 71, 62, 0.08)');ring.setAttribute('stroke-width','30');svg.appendChild(ring);const rawValues=Array.isArray(chartData?.values)?chartData.values:[];const values=rawValues.map((value)=>{const number=Number(value);return Number.isFinite(number)?number:0;});const labels=Array.isArray(chartData?.labels)?chartData.labels:[];const total=values.reduce((sum,value)=>sum+value,0);let startAngle=0;if(total>0){values.forEach((value,idx)=>{if(value<=0){return;}const sliceAngle=(value/total)*360;const endAngle=startAngle+sliceAngle;const path=document.createElementNS('http://www.w3.org/2000/svg','path');path.setAttribute('d',describeArc(100,100,72,startAngle,endAngle));path.setAttribute('fill','none');path.setAttribute('stroke',palette[idx%palette.length]);path.setAttribute('stroke-width','28');path.setAttribute('stroke-linecap','butt');svg.appendChild(path);startAngle=endAngle;});}donut.appendChild(svg);const centerLabel=document.createElement('div');centerLabel.className='donut-center';centerLabel.textContent=total?`${total} jobs`:'0 jobs';donut.appendChild(centerLabel);layout.appendChild(donut);const legend=document.createElement('ul');legend.className='legend-grid';const entryCount=Math.max(labels.length,values.length);for(let idx=0;idx<entryCount;idx+=1){const label=labels[idx]??`Segment ${idx+1}`;const value=values[idx]??0;const item=document.createElement('li');item.className='legend-item';const color=document.createElement('span');color.className='legend-color';color.style.backgroundColor=palette[idx%palette.length];const text=document.createElement('span');const share=total?((value/total)*100).toFixed(1):'0.0';text.textContent=`${label} · ${value} (${share}%)`;item.appendChild(color);item.appendChild(text);legend.appendChild(item);}layout.appendChild(legend);return layout;}function formatParagraphs(narrative){if(!narrative){return [];}return narrative.split('\n').map((line)=>line.trim()).filter((line)=>Boolean(line));}function render(payload){const target=document.getElementById(rootId);if(!target){return;}target.innerHTML='';if(!payload){const empty=document.createElement('div');empty.className='empty-state';empty.textContent='Waiting for telemetry...';target.appendChild(empty);return;}const{report,panel,context,domain}=payload;const content=document.createElement('div');content.className='widget-content';const header=document.createElement('div');header.className='widget-header';const title=document.createElement('div');title.className='widget-title';title.textContent=panel?.title??'Job Correlation';const summary=document.createElement('p');summary.className='widget-summary';summary.textContent=panel?.summary??'';const prompt=document.createElement('p');prompt.className='analysis-prompt';prompt.textContent=panel?.analysisPrompt??'';const contextRow=document.createElement('div');contextRow.className='context-row';const domainTag=document.createElement('span');domainTag.className='context-tag';domainTag.textContent=domain?.name??'Domain';const previewTag=document.createElement('span');previewTag.className='context-tag';previewTag.textContent=`Previews: ${context?.previewCount??0}`;contextRow.appendChild(domainTag);contextRow.appendChild(previewTag);header.appendChild(title);header.appendChild(summary);header.appendChild(prompt);header.appendChild(contextRow);content.appendChild(header);const chartCard=document.createElement('div');chartCard.className='chart-card';const chartTitle=document.createElement('div');chartTitle.className='chart-title';chartTitle.textContent=report?.chart?.title??'Partition demand';chartCard.appendChild(chartTitle);chartCard.appendChild(buildDonut(report?.chart));content.appendChild(chartCard);const narrativeBlock=document.createElement('div');narrativeBlock.className='narrative';const paragraphs=formatParagraphs(report?.narrative?.[0]??'');if(paragraphs.length){paragraphs.forEach((paragraph)=>{const p=document.createElement('p');p.textContent=paragraph;narrativeBlock.appendChild(p);});}else{const p=document.createElement('p');p.textContent='Narrative context is not available for this preview.';narrativeBlock.appendChild(p);}content.appendChild(narrativeBlock);if(Array.isArray(report?.highlights)&&report.highlights.length){const highlightCard=document.createElement('div');highlightCard.className='highlight-card';const highlightTitle=document.createElement('h3');highlightTitle.textContent='Highlights & Interpretation Risks';highlightCard.appendChild(highlightTitle);const list=document.createElement('ul');report.highlights.forEach((entry)=>{const li=document.createElement('li');li.textContent=entry;list.appendChild(li);});highlightCard.appendChild(list);content.appendChild(highlightCard);}target.appendChild(content);requestAnimationFrame(()=>{if(typeof bridge.emit==='function'){const height=target.getBoundingClientRect().height||target.scrollHeight||0;bridge.emit('widget:resize',{height:Math.ceil(height)});}});}bridge.onInit(render);bridge.onUpdate(render);})();